static void WrathIOSMenuPointerReport(const char *stage, const char *reason)
{
	char detail[256];
	if (wrath_ios_menu_pointer.stage_budget == 0)
		return;
	wrath_ios_menu_pointer.stage_budget--;
	dpsnprintf(detail, sizeof(detail), "begins=%u movements=%u drags=%u taps=%u resets=%u; %s",
		wrath_ios_menu_pointer.touch_begins, wrath_ios_menu_pointer.movement_events,
		wrath_ios_menu_pointer.drag_gestures, wrath_ios_menu_pointer.taps_emitted,
		wrath_ios_menu_pointer.resets, reason ? reason : "event recorded");
	WrathIOSRuntimeStage(stage, detail);
}

void WrathIOSMenuPointerReset(const char *reason)
{
	if (wrath_ios_menu_pointer.click_down)
	{
		Key_Event(K_MOUSE1, 0, false);
		wrath_ios_menu_pointer.click_down = false;
	}
	wrath_ios_menu_pointer.active = false;
	wrath_ios_menu_pointer.finger_id = 0;
	wrath_ios_menu_pointer.previous_x = 0;
	wrath_ios_menu_pointer.previous_y = 0;
	wrath_ios_menu_pointer.accumulated_movement = 0;
	wrath_ios_menu_pointer.drag = false;
	wrath_ios_menu_pointer.click_emitted = false;
	wrath_ios_menu_pointer.movement_reported = false;
	memset(multitouch, 0, sizeof(multitouch));
	wrath_ios_menu_pointer.resets++;
	WrathIOSMenuPointerReport(reason && !strcmp(reason, "background") ? "Gate 5B background pointer reset" : "Gate 5B touch state reset", reason);
}

