static void WrathIOSMenuPointerBegin(const SDL_TouchFingerEvent *finger)
{
	if (wrath_ios_menu_pointer.active || key_dest != key_menu)
		return;
	wrath_ios_menu_pointer.active = true;
	wrath_ios_menu_pointer.finger_id = finger->fingerId;
	wrath_ios_menu_pointer.previous_x = finger->x;
	wrath_ios_menu_pointer.previous_y = finger->y;
	wrath_ios_menu_pointer.accumulated_movement = 0;
	wrath_ios_menu_pointer.drag = false;
	wrath_ios_menu_pointer.click_emitted = false;
	wrath_ios_menu_pointer.movement_reported = false;
	wrath_ios_menu_pointer.touch_begins++;
	WrathIOSMenuPointerReport("Gate 5B touch begin", "relative origin established; cursor unchanged");
}

static void WrathIOSMenuPointerMove(const SDL_TouchFingerEvent *finger)
{
	float dx, dy, threshold;
	if (!wrath_ios_menu_pointer.active || finger->fingerId != wrath_ios_menu_pointer.finger_id)
		return;
	dx = (finger->x - wrath_ios_menu_pointer.previous_x) * vid.width * WRATH_IOS_MENU_POINTER_SENSITIVITY;
	dy = (finger->y - wrath_ios_menu_pointer.previous_y) * vid.height * WRATH_IOS_MENU_POINTER_SENSITIVITY;
	wrath_ios_menu_pointer.previous_x = finger->x;
	wrath_ios_menu_pointer.previous_y = finger->y;
	if (dx == 0 && dy == 0)
		return;
	wrath_ios_menu_pointer.accumulated_movement += sqrt(dx * dx + dy * dy);
	threshold = WRATH_IOS_MENU_TAP_THRESHOLD_FRACTION * min(vid.width, vid.height);
	if (!wrath_ios_menu_pointer.drag && wrath_ios_menu_pointer.accumulated_movement >= threshold)
	{
		wrath_ios_menu_pointer.drag = true;
		wrath_ios_menu_pointer.drag_gestures++;
		WrathIOSMenuPointerReport("Gate 5B drag threshold crossed", "gesture is movement-only; finger-up will not click");
	}
	in_windowmouse_x += dx;
	in_windowmouse_y += dy;
	in_windowmouse_x = bound(0, in_windowmouse_x, max(0, vid.width - 1));
	in_windowmouse_y = bound(0, in_windowmouse_y, max(0, vid.height - 1));
	wrath_ios_menu_pointer.movement_events++;
	if (!wrath_ios_menu_pointer.movement_reported)
	{
		wrath_ios_menu_pointer.movement_reported = true;
		WrathIOSMenuPointerReport("Gate 5B relative movement emitted", "normalized finger delta converted once to logical window coordinates");
	}
}

static void WrathIOSMenuPointerEnd(const SDL_TouchFingerEvent *finger)
{
	if (!wrath_ios_menu_pointer.active || finger->fingerId != wrath_ios_menu_pointer.finger_id)
		return;
	if (!wrath_ios_menu_pointer.drag && !wrath_ios_menu_pointer.click_emitted)
	{
		Key_Event(K_MOUSE1, 0, true);
		wrath_ios_menu_pointer.click_emitted = true;
		wrath_ios_menu_pointer.click_down = true;
		wrath_ios_menu_pointer.taps_emitted++;
		WrathIOSMenuPointerReport("Gate 5B tap click emitted", "button down emitted; release deferred to the next engine frame");
	}
	wrath_ios_menu_pointer.active = false;
	wrath_ios_menu_pointer.finger_id = 0;
	wrath_ios_menu_pointer.previous_x = 0;
	wrath_ios_menu_pointer.previous_y = 0;
	wrath_ios_menu_pointer.accumulated_movement = 0;
	wrath_ios_menu_pointer.drag = false;
	wrath_ios_menu_pointer.movement_reported = false;
	wrath_ios_menu_pointer.resets++;
	WrathIOSMenuPointerReport("Gate 5B touch state reset", "finger up");
}
